import {
  Container,
  Typography,
  Card,
  CardContent,
} from "@mui/material";

import "./BoardPage.css";

function BoardPage() {
  const posts = [
    {
      id: 1,
      title: "공지사항",
      author: "관리자",
      content: "게시판 테스트입니다.",
    },
    {
      id: 2,
      title: "React 공부",
      author: "홍길동",
      content: "Material UI 사용 중",
    },
  ];

  return (
    <Container sx={{ mt: 5 }}>
      <Typography variant="h4" gutterBottom>
        게시판
      </Typography>

      {posts.map((post) => (
        <Card key={post.id} sx={{ mb: 3 }}>
          <CardContent>
            <Typography variant="h5">
              {post.title}
            </Typography>

            <Typography color="text.secondary">
              작성자: {post.author}
            </Typography>

            <Typography sx={{ mt: 2 }}>
              {post.content}
            </Typography>
          </CardContent>
        </Card>
      ))}
    </Container>
  );
}

export default BoardPage;
